function solve(n: number): string {
    // Function to convert a number to a given base (hex or base36)
    function convertToBase(num: number, base: number): string {
        if (num === 0) return '0';
        let digits = '';
        while (num > 0) {
            let remainder = num % base;
            if (remainder < 10) {
                digits = remainder.toString() + digits;
            } else {
                digits = String.fromCharCode(65 + remainder - 10) + digits;
            }
            num = Math.floor(num / base);
        }
        return digits;
    }

    // Calculate n squared and n cubed
    const n2 = n * n;
    const n3 = n * n * n;

    // Convert n2 to hexadecimal (base 16)
    const hex = convertToBase(n2, 16);

    // Convert n3 to base36 (digits 0-9 and letters A-Z)
    const base36 = convertToBase(n3, 36);

    // Concatenate and return the result
    return hex + base36;
}

